'use client'
import Link from 'next/link';
import "../globals.css"; 
import React,{FC, useState, useEffect} from 'react';
import NavItems from '../utils/NavItems';
import ThemeSwitcher from "../utils/ThemeSwitcher.tsx";


type Props = {
    open: boolean;
    setOpen: (open: boolean) => void;
    activeItem: number;
}

// Fixed: Destructured the props so activeItem is defined
const Header:FC<Props> = ({ activeItem, setOpen, open }) => {
    const [openSidebar, setOpenSidebar] = useState(false);
    const [active, setActive] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            if (window.scrollY > 80) {
                setActive(true);
            } else {
                setActive(false);
            }
        };

        window.addEventListener("scroll", handleScroll);

        return () => {
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

  return (
    <div className='w-full relative '>
            <div className={`${
            active 
                        ? "bg-gradient-to-r from-black via-purple-950 to-purple-700 fixed top-0 left-0 w-full h-20 z-80 border-b border-purple-900 shadow-xl transition duration-500"
                        : "w-full bg-gradient-to-r from-black via-purple-950 to-purple-700 border-b border-purple-900 h-20 z-80 shadow"
            }`}>
                <div className="w-[95%] m-auto py-2 h-full ">
                     <div className="w-full h-20 flex items-center justify-between p-3">
                         <div>
                            <Link href={"/"} 
                            className={`text-[25px] font-Poppins font-medium text-white` } 
                            >
                                ZyLO Learning
                               </Link>
                         </div>
                         <div className="flex items-center">
                             <NavItems 
                              activeItem={activeItem} 
                              isMobile={false}
                              />
                              <ThemeSwitcher/>
                         </div>
                     </div>
                </div>
            </div>
    </div>
  );
};

export default Header;